import type { MaybeRefOrGetter } from 'vue'
import { randomStr } from '@antfu/utils'
import { computed, onUnmounted, reactive, toValue } from 'vue'
import { useRouter } from '#app/composables/router'
import { useEnabledTabs } from './state-tabs'

export interface CommandItem {
  id: string
  title: string
  description?: string
  icon?: string
  action: () => void | CommandItem[] | Promise<CommandItem[] | void>
}

const registeredCommands = reactive(new Map<string, MaybeRefOrGetter<CommandItem[]>>())

export function useCommands() {
  const tabs = useEnabledTabs()
  const router = useRouter()

  const fixedCommands: CommandItem[] = [
    {
      id: 'fixed:settings',
      title: 'Settings',
      icon: 'carbon-settings-adjust',
      action: () => {
        router.push('/settings')
      },
    },
    {
      id: 'fixed:docs',
      title: 'Nuxt Documentations',
      icon: 'logos-nuxt-icon',
      action: () => {
        return getNuxtDocsCommands()
      },
    },
  ]

  const tabCommands = computed(() => tabs.value
    .map((i): CommandItem => {
      return {
        id: `tab:${i.name}`,
        title: i.title || i.name,
        icon: i.icon,
        action: () => {
          if ('onClick' in i && i.onClick)
            i.onClick()
          else
            router.push(('path' in i && i.path) ? i.path : `/modules/custom-${i.name}`)
        },
      }
    }))

  return computed(() => {
    return [
      ...fixedCommands,
      ...tabCommands.value,
      ...[...registeredCommands.values()]
        .flatMap(i => toValue(i)),
    ]
  })
}

export function registerCommands(getter: MaybeRefOrGetter<CommandItem[]>) {
  const id = randomStr()

  registeredCommands.set(id, getter)

  onUnmounted(() => {
    registeredCommands.delete(id)
  })
}

let _nuxtDocsCommands: CommandItem[] | undefined

export async function getNuxtDocsCommands() {
  if (!_nuxtDocsCommands) {
    const list = await $fetch<any[]>('https://nuxt.com/api/search.json', {
      query: {
        select: '_path,title,description,navigation',
      },
    })
    _nuxtDocsCommands = list.map(i => ({
      id: i._path,
      title: i.title,
      description: i.description,
      icon: i.navigation?.icon ?? 'i-carbon-document-multiple-01',
      action: () => {
        window.open(`https://nuxt.com/${i._path}`, '_blank')
      },
    }))
  }
  return _nuxtDocsCommands
}

import { defineComponent, h } from 'vue'
import type { DefineSetupFnComponent } from 'vue'
import { useLoadingIndicator } from '../composables/loading-indicator'

interface NuxtLoadingIndicatorProps {
  throttle?: number
  duration?: number
  hideDelay?: number
  resetDelay?: number
  height?: number
  color?: string | boolean
  errorColor?: string
  estimatedProgress?: (duration: number, elapsed: number) => number
}

const NuxtLoadingIndicator = defineComponent({
  name: 'NuxtLoadingIndicator',
  props: {
    throttle: {
      type: Number,
      default: 200,
    },
    duration: {
      type: Number,
      default: 2000,
    },
    hideDelay: {
      type: Number,
      default: 500,
    },
    resetDelay: {
      type: Number,
      default: 400,
    },
    height: {
      type: Number,
      default: 3,
    },
    color: {
      type: [String, Boolean],
      default: 'repeating-linear-gradient(to right,#00dc82 0%,#34cdfe 50%,#0047e1 100%)',
    },
    errorColor: {
      type: String,
      default: 'repeating-linear-gradient(to right,#f87171 0%,#ef4444 100%)',
    },
    estimatedProgress: {
      type: Function as unknown as () => (duration: number, elapsed: number) => number,
      required: false,
    },
  },
  setup (props, { slots, expose }) {
    const { progress, isLoading, error, start, finish, clear } = useLoadingIndicator({
      duration: props.duration,
      throttle: props.throttle,
      hideDelay: props.hideDelay,
      resetDelay: props.resetDelay,
      estimatedProgress: props.estimatedProgress,
    })

    expose({
      progress, isLoading, error, start, finish, clear,
    })

    return () => h('div', {
      class: 'nuxt-loading-indicator',
      style: {
        position: 'fixed',
        top: 0,
        right: 0,
        left: 0,
        pointerEvents: 'none',
        width: 'auto',
        height: `${props.height}px`,
        opacity: isLoading.value ? 1 : 0,
        background: error.value ? props.errorColor : props.color || undefined,
        backgroundSize: `${progress.value > 0 ? (100 / progress.value) * 100 : 0}% auto`,
        transform: `scaleX(${progress.value}%)`,
        transformOrigin: 'left',
        transition: 'transform 0.1s, height 0.4s, opacity 0.4s',
        zIndex: 999999,
      },
    }, slots)
  },
}) as unknown as DefineSetupFnComponent<NuxtLoadingIndicatorProps>

export default NuxtLoadingIndicator

import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { defu } from 'defu'
import type { Nuxt } from '@nuxt/schema'
import { dirname, resolve } from 'pathe'
import escapeStringRegexp from 'escape-string-regexp'

import type { Plugin as RollupPlugin } from 'rollup'
import type { Plugin as VitePlugin } from 'vite'

export const SourcemapPreserverPlugin = (nuxt: Nuxt): VitePlugin | VitePlugin[] => {
  let outputDir: string
  const ids = new Set<string>()

  if (!nuxt.options.sourcemap.server || nuxt.options.dev) {
    return []
  }

  const nitroPlugin = () => ({
    name: 'nuxt:sourcemap-import',
    load: {
      filter: {
        id: new RegExp('^(\\w:)?' + escapeStringRegexp(outputDir.replace(/\/?$/, '/')).replace(/\//g, '[\\\\/]')),
      },
      async handler (id) {
        id = resolve(id)
        if (!ids.has(id)) { return }

        const [code, map] = await Promise.all([
          readFile(id, 'utf-8').catch(() => undefined),
          readFile(id + '.map.json', 'utf-8').catch(() => undefined),
        ])

        if (!code) {
          this.warn('Failed loading file')
          return null
        }

        return {
          code,
          map,
        }
      },
    },
  }) satisfies RollupPlugin

  nuxt.hook('nitro:build:before', (nitro) => {
    nitro.options.rollupConfig = defu(nitro.options.rollupConfig, {
      plugins: [nitroPlugin],
    })
  })

  return {
    name: 'nuxt:sourcemap-export',
    applyToEnvironment: (environment) => {
      return environment.name === 'ssr' && environment.config.isProduction
    },
    apply (config) {
      return !!config.build?.sourcemap
    },
    configResolved (config) {
      outputDir = config.build.outDir
    },
    async writeBundle (_options, bundle) {
      for (const chunk of Object.values(bundle)) {
        if (chunk.type !== 'chunk' || !chunk.map) { continue }

        const id = resolve(outputDir, chunk.fileName)
        ids.add(id)
        const dest = id + '.map.json'
        await mkdir(dirname(dest), { recursive: true })
        await writeFile(dest, JSON.stringify({
          file: chunk.map.file,
          mappings: chunk.map.mappings,
          names: chunk.map.names,
          sources: chunk.map.sources,
          sourcesContent: chunk.map.sourcesContent,
          version: chunk.map.version,
        }))
      }
    },
  }
}

import type { ChildProcess } from 'node:child_process'

type VitestTestSummary = {
  failedCount: number
  passedCount: number
  totalCount: number
}

export type SendToHostMessage = {
  started: {
    uiUrl: string | undefined
  }
  updated: VitestTestSummary
  finished: VitestTestSummary
}

export type SendToCliMessage = {
  start: {
    watchMode: boolean
    apiPorts?: number[]
    logToConsole?: boolean
  }
  stop: {
    force?: boolean
  }
}

type ToMessage<T, K extends keyof T> = { type: K, payload: T[K] }
type ToMessages<T> = { [K in keyof T]: ToMessage<T, K> }[keyof T]

function isMessage<T>(message: unknown): message is T {
  return message !== null
    && typeof message === 'object'
    && 'type' in message && message.type !== null && typeof message.type === 'string'
    && 'payload' in message && message.payload !== null && typeof message.payload === 'object'
}

export function createVitestTestSummary(): VitestTestSummary {
  return {
    failedCount: 0,
    passedCount: 0,
    totalCount: 0,
  }
}

export function sendMessageToHost<K extends keyof SendToHostMessage>(
  type: K,
  payload: SendToHostMessage[K],
) {
  process.send?.({ type, payload })
}

export function listenHostMessages(
  listener: (message: ToMessages<SendToCliMessage>) => unknown,
) {
  process.on('message', (message) => {
    if (isMessage<ToMessages<SendToCliMessage>>(message)) {
      listener(message)
    }
  })
}

export function sendMessageToCli<K extends keyof SendToCliMessage>(
  cli: ChildProcess,
  type: K,
  payload: SendToCliMessage[K],
) {
  cli.send({ type, payload })
}

export function listenCliMessages(
  cli: ChildProcess,
  listener: (message: ToMessages<SendToHostMessage>) => unknown,
) {
  cli.on('message', (message) => {
    if (isMessage<ToMessages<SendToHostMessage>>(message)) {
      listener(message)
    }
  })
}

import { ref, onScopeDispose } from 'vue'
