import type { Nuxt } from '@nuxt/schema'
import type { ModuleOptions } from './module'
import { addTypeTemplate, isNuxtMajorVersion } from '@nuxt/kit'

interface TemplateContext {
  nuxt: Nuxt
  config: ModuleOptions
}

export function registerTypeTemplates({ nuxt }: TemplateContext) {
  // Nuxt 4 ships Nitro v3, which exposes `nitropack/types` as a public subpath.
  // @nuxt/kit's extendRouteRules unions NitroRouteConfig across both 'nitropack'
  // and 'nitropack/types', so augmenting only one leaves the other's re-exported
  // interface without our `robots` key.
  const nitroModules = isNuxtMajorVersion(4, nuxt)
    ? ['nitropack', 'nitropack/types']
    : ['nitropack']

  // Nuxt-only type augmentations (PageMeta)
  addTypeTemplate({
    filename: 'types/nuxt-robots-nuxt.d.ts',
    getContents: () => `// Generated by nuxt-robots
import type { RobotsValue } from '@nuxtjs/robots'

declare module '#app' {
  interface PageMeta {
    robots?: RobotsValue
  }
}

export {}
`,
  }, {
    nuxt: true,
  })

  const nitroAugmentation = (mod: string) => `declare module '${mod}' {
  interface NitroApp {
    _robots: {
      ctx: HookRobotsConfigContext
      nuxtContentUrls?: Set<string>
    },
    _robotsRuleMatcher: (url: string) => any
    _robotsPatternMap?: Map<string, PatternMapValue>
  }
  interface NitroRouteRules {
    robots?: RobotsValue | {
      indexable: boolean
      rule: string
    }
  }
  interface NitroRouteConfig {
    robots?: RobotsValue | {
      indexable: boolean
      rule: string
    }
  }
  interface NitroRuntimeHooks {
    'robots:config': (ctx: HookRobotsConfigContext) => void | Promise<void>
    'robots:robots-txt': (ctx: HookRobotsTxtContext) => void | Promise<void>
  }
}`

  // Nitro type augmentations (NitroApp, NitroRouteRules, NitroRouteConfig, NitroRuntimeHooks, H3EventContext)
  addTypeTemplate({
    filename: 'types/nuxt-robots-nitro.d.ts',
    getContents: () => `// Generated by nuxt-robots
import type { HookRobotsConfigContext, HookRobotsTxtContext, RobotsValue, RobotsContext, PatternMapValue } from '@nuxtjs/robots'

${nitroModules.map(nitroAugmentation).join('\n\n')}

declare module 'h3' {
  interface H3EventContext {
    robots: RobotsContext
    robotsProduction?: RobotsContext
  }
}

export {}
`,
  }, {
    nitro: true,
    nuxt: true,
  })
}

import type { SitemapWarning } from './parseSitemapXml'

export interface SitemapIndexEntry {
  loc: string
  lastmod?: string
}

export interface SitemapIndexParseResult {
  entries: SitemapIndexEntry[]
  warnings: SitemapWarning[]
}

interface ParsedSitemap {
  loc?: string
  lastmod?: string
}

interface ParsedSitemapIndex {
  sitemap?: ParsedSitemap | ParsedSitemap[]
}

interface ParsedRoot {
  sitemapindex?: ParsedSitemapIndex
}

function isValidUrl(value: string): boolean {
  return URL.canParse(value)
}

export async function parseSitemapIndex(xml: string): Promise<SitemapIndexParseResult> {
  if (!xml)
    throw new Error('Empty XML input provided')

  const { XMLParser } = await import('fast-xml-parser')
  const parser = new XMLParser({
    isArray: (tagName: string) => tagName === 'sitemap',
    removeNSPrefix: true,
    trimValues: true,
  })
  const parsed = parser.parse(xml) as ParsedRoot

  if (parsed?.sitemapindex === undefined)
    throw new Error('XML does not contain a valid sitemapindex element')

  if (!parsed.sitemapindex || !parsed.sitemapindex.sitemap)
    return { entries: [], warnings: [] }

  const sitemaps = Array.isArray(parsed.sitemapindex.sitemap)
    ? parsed.sitemapindex.sitemap
    : [parsed.sitemapindex.sitemap]

  const warnings: SitemapWarning[] = []
  const entries: SitemapIndexEntry[] = []

  for (const s of sitemaps) {
    if (typeof s.loc !== 'string' || !s.loc.trim().length) {
      warnings.push({
        type: 'validation',
        message: 'Sitemap entry missing required loc element',
      })
      continue
    }
    const loc = s.loc.trim()
    if (!isValidUrl(loc)) {
      warnings.push({
        type: 'validation',
        message: 'Sitemap entry has invalid URL',
        context: { url: loc },
      })
      continue
    }
    entries.push({
      loc,
      ...(s.lastmod && { lastmod: s.lastmod.trim() }),
    })
  }

  return { entries, warnings }
}

export function isSitemapIndex(xml: string): boolean {
  return xml.includes('<sitemapindex') || xml.includes('sitemapindex>')
}

import type { FetchError, FetchOptions } from 'ofetch'
import type { Strapi3Error } from '../types/v3'
import type { Strapi4Error } from '../types/v4'
import type { Strapi5Error } from '../types/v5'
import { stringify } from '../utils/stringify'
import { useStrapiUrl } from './useStrapiUrl'
import { useStrapiVersion } from './useStrapiVersion'
import { useStrapiToken } from './useStrapiToken'
import { useNuxtApp } from '#imports'

const defaultErrors = (err: FetchError) => ({
  v5: {
    error: {
      status: 500,
      name: 'UnknownError',
      message: err.message,
      details: err
    }
  },
  v4: {
    error: {
      status: 500,
      name: 'UnknownError',
      message: err.message,
      details: err
    }
  },
  v3: {
    error: 'UnknownError',
    message: err.message,
    statusCode: 500
  }
})

export const useStrapiClient = () => {
  const nuxt = useNuxtApp()
  const baseURL = useStrapiUrl()
  const version = useStrapiVersion()
  const token = useStrapiToken()

  return async <T> (url: string, fetchOptions: FetchOptions = {}): Promise<T> => {
    const headers: HeadersInit = {}

    if (token && token.value) {
      headers.Authorization = `Bearer ${token.value}`
    }

    // Map params according to strapi v3 and v4 formats
    if (fetchOptions.params) {
      const params = stringify(fetchOptions.params as Record<string, unknown>)
      if (params) {
        url = `${url}?${params}`
      }
      fetchOptions = { ...fetchOptions }
      delete fetchOptions.params
    }

    try {
      // @ts-expect-error method is not explicitly typed
      return await $fetch<T>(url, {
        retry: 0,
        baseURL,
        ...fetchOptions,
        headers: {
          ...headers,
          ...fetchOptions.headers
        }
      })
    } catch (err) {
      const e: Strapi3Error | Strapi4Error | Strapi5Error = err.data || defaultErrors(err)[version]

      nuxt.hooks.callHook('strapi:error', e)
      throw e
    }
  }
}

declare module '#app' {
  interface RuntimeNuxtHooks {
    'strapi:error': (error: Strapi3Error | Strapi4Error | Strapi5Error) => void
  }
}

import type { StrapiFilterRequestParam, StrapiLocale, StrapiRequestParamField, StrapiRequestParamPopulate, StrapiRequestParamSort } from '.'

export interface Strapi4Error {
  error: {
    status: number
    name: string
    message: string
    details: Record<string, unknown>
  }
}

export interface PaginationByPage {
  page: number
  pageSize: number
  withCount?: boolean
}

export interface PaginationByOffset {
  start: number
  limit: number
  withCount?: boolean
}

export interface Strapi4RequestParams<T> {
  fields?: Array<StrapiRequestParamField<T>>
  populate?: Strapi4RequestPopulateParam<T>
  sort?: StrapiRequestParamSort<T> | Array<StrapiRequestParamSort<T>>
  pagination?: PaginationByOffset | PaginationByPage
  filters?: StrapiFilterRequestParam<T>
  publicationState?: 'live' | 'preview'
  locale?: StrapiLocale
}

export type Strapi4RequestPopulateParams<T> = Pick<Strapi4RequestParams<T>, 'fields' | 'sort' | 'populate' | 'filters'>

// Unified type for Strapi populate, combining both string paths and nested objects.
export type Strapi4RequestPopulateParam<T>
  = | '*' // Populate all relations.
    | { [K in keyof T]?: // Nested object population.
      T[K] extends object
        ? T[K] extends Array<infer I>
          ? Strapi4RequestPopulateParam<I> | Strapi4RequestPopulateParams<I>
          : Strapi4RequestPopulateParam<T[K]> | Strapi4RequestPopulateParams<T[K]>
        : never
    }
    | StrapiRequestParamPopulate<T> // String paths like "field.subfield".
    | Array<StrapiRequestParamPopulate<T>> // Array of string paths.

export interface Strapi4ResponseData<T> {
  id: number
  attributes: T
  meta: Record<string, unknown>
}

export interface Strapi4Response<T> {
  data: Strapi4ResponseData<T> | Strapi4ResponseData<T>[]
  meta: Strapi4ResponseMeta
}

export interface Strapi4ResponseSingle<T> {
  data: Strapi4ResponseData<T>
  meta: Strapi4ResponseMeta
}

export interface Strapi4ResponseMany<T> {
  data: Strapi4ResponseData<T>[]
  meta: Strapi4ResponseMeta
}

export interface Strapi4ResponseMeta {
  pagination: MetaResponsePaginationByPage | MetaResponsePaginationByOffset
  [key: string]: unknown
}

export interface MetaResponsePaginationByPage {
  page: number
  pageSize: number
  pageCount: number
  total: number
}

export interface MetaResponsePaginationByOffset {
  start: number
  limit: number
  total: number
}

