import { ipxHttpStorage } from "./storage/http.ts";

// ---- CLI parsing ----
const { positionals, values } = parseArgs({
  allowPositionals: true,
  options: {
    dir: { type: "string" },
    domains: { type: "string" },
    port: { type: "string" },
    host: { type: "string" },
    help: { type: "boolean", short: "h" },
    version: { type: "boolean", short: "v" },
  },
});

const [command] = positionals;

// ---- Global flags ----
if (values.version) {
  console.log(`${pkg.name} ${pkg.version}`);
  process.exit(0);
}

if (values.help || !command) {
  printHelp();
  process.exit(0);
}

// ---- Commands ----
switch (command) {
  case "serve": {
    await runServe(values);
    break;
  }
  default: {
    console.error(`Unknown command: ${command}\n`);
    printHelp();
    process.exit(1);
  }
}

// ---- Command impl ----
async function runServe(args) {
  const ipx = createIPX({
    storage: ipxFSStorage({
      dir: args.dir ?? process.env.IPX_FS_DIR ?? process.cwd(),
    }),
    httpStorage: ipxHttpStorage({
      domains: args.domains ?? process.env.IPX_HTTP_DOMAINS,
    }),
  });

  const server = serveIPX(ipx, {
    port: Number(args.port ?? process.env.PORT ?? 3000),
    hostname: args.host ?? process.env.HOST ?? "0.0.0.0",
  });

  await server.ready();
}

// ---- Help output ----
function printHelp() {
  console.log(`
${pkg.name} ${pkg.version}

Usage:
  ipx serve [options]

Commands:
  serve                   Start IPX server

Options:
  --dir <dir>             Directory to serve (ENV: IPX_FS_DIR)
  --domains <list>        Allowed domains (comma separated, ENV: IPX_HTTP_DOMAINS)
  --port <number>         Port to listen (default: 3000, ENV: PORT)
  --host <host>           Host to bind (default: 0.0.0.0, ENV: HOST)
  -h, --help              Show help
  -v, --version           Show version
`);
}

import { consola } from "consola";
import { Hookable, createDebugger } from "hookable";
import type { LoadConfigOptions, Nitro, NitroConfig, NitroDynamicConfig } from "nitro/types";
import { version as nitroVersion } from "nitro/meta";
import { loadOptions } from "./config/loader.ts";
import { updateNitroConfig } from "./config/update.ts";
import { installModules } from "./module.ts";
import { scanAndSyncOptions, scanHandlers } from "./scan.ts";
import { initNitroRouting } from "./routing.ts";
import { registerNitroInstance } from "./global.ts";

export async function createNitro(
  config: NitroConfig = {},
  opts: LoadConfigOptions = {}
): Promise<Nitro> {
  // Resolve options
  const options = await loadOptions(config, opts);

  // Create nitro context
  const nitro: Nitro = {
    meta: {
      version: nitroVersion,
      majorVersion: 3,
    },
    options,
    hooks: new Hookable(),
    vfs: new Map(),
    routing: {} as any,
    logger: consola.withTag("nitro"),
    scannedHandlers: [],
    fetch: () => {
      throw new Error("no dev server attached!");
    },
    close: () => Promise.resolve(nitro.hooks.callHook("close")),
    async updateConfig(config: NitroDynamicConfig) {
      updateNitroConfig(nitro, config);
    },
  };

  // Global setup
  registerNitroInstance(nitro);

  // Init routers
  initNitroRouting(nitro);

  // Scan dirs (plugins, tasks, modules) and sync options
  // TODO: Make it side-effect free to allow proper watching
  await scanAndSyncOptions(nitro);

  // Debug
  if (nitro.options.debug) {
    createDebugger(nitro.hooks, { tag: "nitro" });
  }

  // Logger
  if (nitro.options.logLevel !== undefined) {
    nitro.logger.level = nitro.options.logLevel;
  }

  // Hooks
  nitro.hooks.addHooks(nitro.options.hooks);

  // Scan and install modules
  await installModules(nitro);

  // Auto imports
  if (nitro.options.imports) {
    // Create unimport instance
    const { createUnimport } = await import("unimport");
    nitro.unimport = createUnimport(nitro.options.imports);
    await nitro.unimport.init();
    // Support for importing from '#imports'
    nitro.options.virtual["#imports"] = () => nitro.unimport?.toExports() || "";
    // Backward compatibility
    nitro.options.virtual["#nitro"] = 'export * from "#imports"';
  }

  // Ensure initial handlers are populated
  await scanHandlers(nitro);

  // Sync routers
  nitro.routing.sync();

  return nitro;
}

import { type DriverFactory } from "./utils/index.ts";

const DRIVER_NAME = "memory";

const driver: DriverFactory<void, Map<string, any>> = () => {
  const data = new Map<string, any>();
  const timers = new Map<string, ReturnType<typeof setTimeout>>();

  return {
    name: DRIVER_NAME,
    getInstance: () => data,
    hasItem(key) {
      return data.has(key);
    },
    getItem(key) {
      return data.get(key) ?? null;
    },
    getItemRaw(key) {
      return data.get(key) ?? null;
    },
    setItem(key, value, opts) {
      _clearTimer(timers, key);
      data.set(key, value);
      _scheduleExpiry(data, timers, key, opts?.ttl);
    },
    setItemRaw(key, value, opts) {
      _clearTimer(timers, key);
      data.set(key, value);
      _scheduleExpiry(data, timers, key, opts?.ttl);
    },
    removeItem(key) {
      _clearTimer(timers, key);
      data.delete(key);
    },
    getKeys() {
      return [...data.keys()];
    },
    clear() {
      for (const timer of timers.values()) {
        clearTimeout(timer);
      }
      timers.clear();
      data.clear();
    },
    dispose() {
      for (const timer of timers.values()) {
        clearTimeout(timer);
      }
      timers.clear();
      data.clear();
    },
  };
};

export default driver;

// --- Internal helpers ---

function _clearTimer(timers: Map<string, ReturnType<typeof setTimeout>>, key: string) {
  const existing = timers.get(key);
  if (existing !== undefined) {
    clearTimeout(existing);
    timers.delete(key);
  }
}

function _scheduleExpiry(
  data: Map<string, any>,
  timers: Map<string, ReturnType<typeof setTimeout>>,
  key: string,
  ttl?: number,
) {
  if (!ttl) {
    return;
  }
  const ttlMs = ttl * 1000;
  const timer = setTimeout(() => {
    data.delete(key);
    timers.delete(key);
  }, ttlMs);
  if (timer && typeof timer === "object" && "unref" in timer) {
    timer.unref();
  }
  timers.set(key, timer);
}

import { type DriverFactory } from "./utils/index.ts";
import type { Driver } from "unstorage";
import { normalizeKey } from "./utils/index.ts";

export interface OverlayStorageOptions {
  layers: Driver[];
}

const OVERLAY_REMOVED = "__OVERLAY_REMOVED__";

const DRIVER_NAME = "overlay";

const driver: DriverFactory<OverlayStorageOptions> = (options) => {
  return {
    name: DRIVER_NAME,
    options: options,
    async hasItem(key, opts) {
      for (const layer of options.layers) {
        if (await layer.hasItem(key, opts)) {
          if (
            layer === options.layers[0] &&
            (await options.layers[0]?.getItem(key)) === OVERLAY_REMOVED
          ) {
            return false;
          }
          return true;
        }
      }
      return false;
    },
    async getItem(key) {
      for (const layer of options.layers) {
        const value = await layer.getItem(key);
        if (value === OVERLAY_REMOVED) {
          return null;
        }
        if (value !== null) {
          return value;
        }
      }
      return null;
    },
    // TODO: Support native meta
    // async getMeta (key) {},
    async setItem(key, value, opts) {
      await options.layers[0]?.setItem?.(key, value, opts);
    },
    async removeItem(key, opts) {
      await options.layers[0]?.setItem?.(key, OVERLAY_REMOVED, opts);
    },
    async getKeys(base, opts) {
      const allKeys = await Promise.all(
        options.layers.map(async (layer) => {
          const keys = await layer.getKeys(base, opts);
          return keys.map((key) => normalizeKey(key));
        }),
      );
      const uniqueKeys = [...new Set(allKeys.flat())];
      const existingKeys = await Promise.all(
        uniqueKeys.map(async (key) => {
          if ((await options.layers[0]?.getItem(key)) === OVERLAY_REMOVED) {
            return false;
          }
          return key;
        }),
      );
      return existingKeys.filter(Boolean) as string[];
    },
    async dispose() {
      // TODO: Graceful error handling
      await Promise.all(
        options.layers.map(async (layer) => {
          if (layer.dispose) {
            await layer.dispose();
          }
        }),
      );
    },
  };
};

export default driver;
